module comparator_4bit(a, b, greater_than, eq, gt);

    input [3:0] a, b;
    output reg greater_than, eq, gt;

    always @(*)
        begin
            if (a < b)
                begin
                    greater_than = 1;
                    eq = 0;
                    gt = 0;
                end
            else if (a == b)
                begin
                    greater_than = 0;
                    eq = 1;
                    gt = 0;
                end
            else
                begin
                    greater_than = 0;
                    eq = 0;
                    gt = 1;
                end
        end

endmodule
